// frontend/src/pages/HomePage.js — Phase 2: fetches posts from GET /api/posts
import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const HomePage = () => {
  const [posts,   setPosts]   = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <main className='container'><p style={{ textAlign:'center', padding:'3rem', fontStyle:'italic' }}>Loading posts...</p></main>;

  return (
    <main className='container'>
      <section style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'30px', flexWrap:'wrap', gap:'12px' }}>
        <h2 style={{ fontFamily:"'Cinzel', serif", borderBottom:'3px solid var(--accent)', paddingBottom:'8px' }}>Latest Chess Posts</h2>
        {user && <Link to='/create-post' className='btn-primary' style={{ textDecoration:'none' }}>+ Write a Post</Link>}
      </section>

      {posts.length === 0 && (
        <div className='card-warm' style={{ textAlign:'center', padding:'3rem' }}>
          <p>No posts yet. {user ? <Link to='/create-post'>Be the first!</Link> : <><Link to='/register'>Register</Link> to start writing.</>}</p>
        </div>
      )}

      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(280px, 1fr))', gap:'24px' }}>
        {posts.map(post => (
          <div key={post._id} className='card-warm' style={{ padding:'20px', display:'flex', flexDirection:'column', gap:'10px' }}>
            {post.image && (
              <img src={`http://localhost:5000/uploads/${post.image}`} alt={post.title}
                style={{ width:'100%', height:180, objectFit:'cover', borderRadius:'8px', margin:0 }} />
            )}
            <h3 style={{ fontFamily:"'Cinzel', serif", fontSize:'1rem' }}>
              <Link to={`/posts/${post._id}`} style={{ color:'var(--text-color)' }}>{post.title}</Link>
            </h3>
            <p style={{ color:'var(--text-secondary)', fontSize:'0.95rem', flexGrow:1 }}>
              {post.body.substring(0, 120)}{post.body.length > 120 ? '...' : ''}
            </p>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:'0.82rem', color:'var(--accent)' }}>
              <span style={{ display:'flex', alignItems:'center', gap:'6px' }}>
                {post.author?.profilePic && (
                  <img src={`http://localhost:5000/uploads/${post.author.profilePic}`} alt=''
                    style={{ width:24, height:24, borderRadius:'50%', objectFit:'cover', margin:0 }} />
                )}
                {post.author?.name}
              </span>
              <span>{new Date(post.createdAt).toLocaleDateString()}</span>
            </div>
            <Link to={`/posts/${post._id}`} style={{ fontSize:'0.85rem', fontFamily:"'Cinzel', serif" }}>Read more →</Link>
          </div>
        ))}
      </div>
    </main>
  );
};
export default HomePage;
